            int current = current_level[i];
            if (current == dest) {
                return distance;
            }
            for (int j = 0; j < N; j++) {
                if (A[current * N + j] && !visited[j]) {
                    #pragma omp critical
                    {
                        if (!visited[j]) {
                            visited[j] = true;
                            next_level.push_back(j);
                        }
                    }
                }
            }
        }
