        k >>= 1;
        phiT = phiT * phiT;
        T = 1.0L;
        for (unsigned int l = 0; l < k; l++) {
            #pragma omp parallel for
            for (unsigned int a = l; a < N; a += n) {
                unsigned int b = a + k;
                std::complex<double> t = x_copy[a] - x_copy[b];
                x_copy[a] += x_copy[b];
                x_copy[b] = t * T;
            }
            T *= phiT;
        }
    }

    unsigned int m = static_cast<unsigned int>(std::log2(N));
    #pragma omp parallel for
    for (unsigned int a = 0; a < N; a++) {
        unsigned int b = a;
