            int cell = input[i * N + j];
            int sum = 0;
            if (i > 0) sum += input[(i - 1) * N + j];
            if (i < N - 1) sum += input[(i + 1) * N + j];
            if (j > 0) sum += input[i * N + (j - 1)];
            if (j < N - 1) sum += input[i * N + (j + 1)];
