size_t findClosestToPi(std::vector<double> const& x) {
    size_t n = x.size();
    if (n == 0) return 0;

    double pi = M_PI;
    size_t best_idx = 0;
    double best_diff = std::abs(x[0] - pi);

    #pragma omp parallel for schedule(static)
    for (size_t i = 1; i < n; ++i) {
        double diff = std::abs(x[i] - pi);
        if (diff < best_diff) {
            best_diff = diff;
            best_idx = i;
        }
    }

    return best_idx;
}
